mapper.sql:
left join re_recruitment rr on convert(bigint, rr.attribute4) = rrti.id AND convert(bigint, rr.attribute5) = rrti.group_id
where 1 = 1
and rrti.group_id = #{criteria.groupId,jdbcType=BIGINT}
and rrti.data_status = #{criteria.dataStatus,jdbcType=VARCHAR}
and ( rrti.job_name like #{criteria.recruitmentQuery,jdbcType=VARCHAR} or rrti.dept_name like #{criteria.recruitmentQuery,jdbcType=VARCHAR} or rrti.name like #{criteria.recruitmentQuery,jdbcType=VARCHAR} or rrti.gender like #{criteria.recruitmentQuery,jdbcType=VARCHAR} or rrti.height like #{criteria.recruitmentQuery,jdbcType=VARCHAR} or rrti.weight like #{criteria.recruitmentQuery,jdbcType=VARCHAR} or rrti.native_place like #{criteria.recruitmentQuery,jdbcType=VARCHAR} or rrti.nation like #{criteria.recruitmentQuery,jdbcType=VARCHAR} or rrti.marital_status like #{criteria.recruitmentQuery,jdbcType=VARCHAR} or rrti.political like #{criteria.recruitmentQuery,jdbcType=VARCHAR} or rrti.mobile_phone like #{criteria.recruitmentQuery,jdbcType=VARCHAR} or rrti.email like #{criteria.recruitmentQuery,jdbcType=VARCHAR} or rrti.address like #{criteria.recruitmentQuery,jdbcType=VARCHAR} or rrti.id_number like #{criteria.recruitmentQuery,jdbcType=VARCHAR} or rrti.entry_time like #{criteria.recruitmentQuery,jdbcType=VARCHAR})
